	}
}

// The main protocol description for HMQV two pass
symmetric-role protocol HMQV-twopass(I,R)
{
	role I
	{
		fresh x: Nonce; // Fresh nonce generated by I
		var Y: Ticket;   // Ticket received from R

		// I sends its public value of x
		send_1(I,R, gexp(x) );
		// I receives a ticket from R
		recv_2(R,I, Y );

		// I computes a symmetric key SKR based on exchanged values
		claim(I,SKR,    KDF(exp(mult(Y,exp(gexp(sk(R)),H(Y,I))),add(x,mult(H(gexp(x),R),sk(I))))) );
	}	

	role R
	{
		fresh y: Nonce; // Fresh nonce generated by R
		var X: Ticket;   // Ticket received from I

		// R receives the public value of x from I
		recv_1(I,R, X );
		// R sends its public value of y to I
		send_2(R,I, gexp(y) );

		// R computes a symmetric key SKR based on exchanged values
		claim(R,SKR,    KDF(exp(mult(X,exp(gexp(sk(I)),H(X,R))),add(y,mult(H(gexp(y),I),sk(R))))) );
	}
}

